// ===============================
// CAPTURA EXECUÇÕES
// ===============================

const executions = $input.all().map(i => i.json);

// Últimos 30 dias
const now = new Date();
const last30Days = new Date();
last30Days.setDate(now.getDate() - 30);

// Filtra execuções válidas
const recentExecutions = executions.filter(e => {
  if (!e.startedAt || !e.stoppedAt) return false;

  const started = new Date(e.startedAt);
  return started >= last30Days && started <= now;
});

// ===============================
// MÉTRICAS TÉCNICAS
// ===============================

const totalExecutions = recentExecutions.length;

const failedExecutions = recentExecutions.filter(
  e => e.status !== 'success'
).length;

const failureRate =
  totalExecutions === 0
    ? 0
    : (failedExecutions / totalExecutions) * 100;

let totalExecutionTimeMs = 0;

recentExecutions.forEach(e => {
  const start = new Date(e.startedAt);
  const end = new Date(e.stoppedAt);
  totalExecutionTimeMs += (end - start);
});

const avgExecutionTimeMs =
  totalExecutions === 0
    ? 0
    : totalExecutionTimeMs / totalExecutions;

// ===============================
// TEMPO ECONOMIZADO
// ===============================

const MINUTOS_ECONOMIZADOS_POR_EXECUCAO = 5;

const tempoEconomizadoMinutos =
  totalExecutions * MINUTOS_ECONOMIZADOS_POR_EXECUCAO;

const tempoEconomizadoHoras =
  tempoEconomizadoMinutos / 60;

// ===============================
// MÉTRICAS EXECUTIVAS
// ===============================

const HORAS_DIA = 8;
const HORAS_MES = 160;

const funcionariosEquivalentes =
  tempoEconomizadoHoras / HORAS_MES;

const diasTrabalhoEconomizados =
  tempoEconomizadoHoras / HORAS_DIA;

const mesesHumanosEconomizados =
  tempoEconomizadoHoras / HORAS_MES;

// ===============================
// MÉTRICAS FINANCEIRAS
// ===============================

const CUSTO_MEDIO_FUNCIONARIO = 4000;
const CUSTO_INFRAESTRUTURA_MENSAL = 250;

// Economia em salários
const economiaSalarios =
  funcionariosEquivalentes * CUSTO_MEDIO_FUNCIONARIO;

// Economia líquida (ROI em R$)
const economiaLiquida =
  economiaSalarios - CUSTO_INFRAESTRUTURA_MENSAL;

// ===============================
// CUSTOS UNITÁRIOS
// ===============================

const TOTAL_AUTOMACOES_ATIVAS = 10; // ajuste conforme seu cenário

const custoPorAutomacao =
  TOTAL_AUTOMACOES_ATIVAS === 0
    ? 0
    : CUSTO_INFRAESTRUTURA_MENSAL / TOTAL_AUTOMACOES_ATIVAS;

const custoPorExecucao =
  totalExecutions === 0
    ? 0
    : CUSTO_INFRAESTRUTURA_MENSAL / totalExecutions;

// ROI em R$
const roiFinanceiroMensalReais = economiaLiquida;

// ===============================
// OUTPUT FINAL
// ===============================

return [
  {
    json: {
      periodo: "ultimos_30_dias",

      // Execuções
      execucoes_producao: totalExecutions,
      execucoes_com_falha: failedExecutions,
      taxa_falha_percentual: Number(failureRate.toFixed(2)),
      tempo_medio_execucao_segundos:
        Number((avgExecutionTimeMs / 1000).toFixed(2)),

      // Tempo economizado
      tempo_economizado_minutos: tempoEconomizadoMinutos,
      tempo_economizado_horas:
        Number(tempoEconomizadoHoras.toFixed(2)),

      // Impacto operacional
      funcionarios_equivalentes:
        Number(funcionariosEquivalentes.toFixed(2)),

      dias_trabalho_economizados:
        Number(diasTrabalhoEconomizados.toFixed(0)),

      meses_humanos_economizados:
        Number(mesesHumanosEconomizados.toFixed(2)),

      // 💰 FINANCEIRO EXECUTIVO
      custo_medio_funcionario: CUSTO_MEDIO_FUNCIONARIO,
      custo_infraestrutura_mensal: CUSTO_INFRAESTRUTURA_MENSAL,

      economia_salarios_mensal:
        Number(economiaSalarios.toFixed(2)),

      economia_liquida_mensal:
        Number(economiaLiquida.toFixed(2)),

      roi_financeiro_mensal_reais:
        Number(roiFinanceiroMensalReais.toFixed(2)),

      // 🧠 CUSTOS UNITÁRIOS
      custo_por_automacao:
        Number(custoPorAutomacao.toFixed(2)),

      custo_por_execucao:
        Number(custoPorExecucao.toFixed(6))
    }
  }
];

// Pega todos os itens do nó "dados"
const dados = $('Code in JavaScript').all();

// Retorna exatamente o que veio do nó "dados"
return dados;

